// // This module implements an 8-bit binary up-counter with both synchronous reset and enable. When the reset signal is asserted, the counter should reset to 0. The counter should increment its value on each positive edge of the clock if the enable signal is asserted.
module sync_down_counter_8bit_with_reset (
    input wire clk,
    input wire rst,
    input wire en,
    output reg [7:0] count
);

    always @(posedge clk) begin
        if (rst) begin
            count <= 8'b11111111;
        end else if (en) begin
            count <= count - 1;
        end
    end

endmodule
